typedef enum _EC_SUBSCRIPTION_CONFIGURATION_MODE {
    EcConfigurationModeNormal,
    EcConfigurationModeCustom
} EC_SUBSCRIPTION_CONFIGURATION_MODE;

typedef enum _EC_SUBSCRIPTION_CONTENT_FORMAT {
    EcSubscriptionContentFormatEvents,
    EcSubscriptionContentFormatRenderedText
} EC_SUBSCRIPTION_CONTENT_FORMAT;

typedef enum _EC_SUBSCRIPTION_CREDENTIALS_TYPE {
  EcSubscriptionCommonUserName,
  EcSubscriptionCommonPassword,
  EcSubscriptionHostName
} EC_SUBSCRIPTION_CREDENTIALS_TYPE;

typedef enum _EC_SUBSCRIPTION_RUNTIME_STATUS_ACTIVE_STATUS {   EcRuntimeStatusActiveStatusDisabled = 1,
EcRuntimeStatusActiveStatusActive,   EcRuntimeStatusActiveStatusInactive,   EcRuntimeStatusActiveStatusTrying
} EC_SUBSCRIPTION_RUNTIME_STATUS_ACTIVE_STATUS;

BOOL EcDeleteSubscription(
[in] LPCWSTR SubscriptionName,
[in] DWORD   Flags);

BOOL EcSaveSubscription(
[in] EC_HANDLE Subscription,
[in] DWORD     Flags);

BOOL EcSetObjectArrayProperty(
[in] EC_OBJECT_ARRAY_PROPERTY_HANDLE ObjectArray,   [in] EC_SUBSCRIPTION_PROPERTY_ID     PropertyId,   [in] DWORD                           ArrayIndex,   [in] DWORD                           Flags,
[in] PEC_VARIANT                     PropertyValue);

typedef struct _EC_VARIANT {
  union {
    BOOL BooleanVal;
    UINT32 UInt32Val;
    ULONGLONG DateTimeVal;
    LPCWSTR StringVal;
    PBYTE BinaryVal;
    BOOL *BooleanArr;
    INT32 *Int32Arr;
    LPWSTR *StringArr;
  };
} EC_VARIANT;

BOOL EcGetObjectArraySize(
[in]  EC_OBJECT_ARRAY_PROPERTY_HANDLE ObjectArray,
[out] PDWORD                          ObjectArraySize);

BOOL EcSetSubscriptionProperty(
[in] EC_HANDLE                   Subscription,   [in] EC_SUBSCRIPTION_PROPERTY_ID PropertyId,   [in] DWORD                       Flags,
[in] PEC_VARIANT                 PropertyValue);
